import java.util.*;

public class Dependency {
    private String name;
    private String version;

    public Dependency(String name, String version) {
        this.name = name;
        this.version = version;
    }

    @Override
    public String toString() { return name + ":" + version; }
}

public class SpringBootStarter {
    private String starterName;
    private List<Dependency> bundledDeps;

    public SpringBootStarter(String name, List<Dependency> deps) {
        this.starterName = name;
        this.bundledDeps = deps;
    }

    public void printStarterContents() {
        System.out.println("Starter: " + starterName);
        bundledDeps.forEach(d -> System.out.println("  + " + d));
    }
}

public class ProjectDependencies {
    private Set<Dependency> resolvedDeps = new LinkedHashSet<>();

    public void addStarter(SpringBootStarter starter) {
        // TODO: Add all starter's bundled deps to resolvedDeps
    }

    public void printResolved() {
        System.out.println("Resolved dependencies (" + resolvedDeps.size() + " total):");
        resolvedDeps.forEach(d -> System.out.println("  " + d));
    }
}

public class Main {
    public static void main(String[] args) {
        // Create spring-boot-starter-web starter
        SpringBootStarter webStarter = new SpringBootStarter("spring-boot-starter-web",
            Arrays.asList(
                new Dependency("spring-webmvc", "6.1.0"),
                new Dependency("tomcat-embed-core", "10.1.0"),
                new Dependency("jackson-databind", "2.15.0")
            ));

        SpringBootStarter testStarter = new SpringBootStarter("spring-boot-starter-test",
            Arrays.asList(
                new Dependency("junit-jupiter", "5.10.0"),
                new Dependency("mockito-core", "5.4.0"),
                new Dependency("spring-test", "6.1.0")
            ));

        webStarter.printStarterContents();
        testStarter.printStarterContents();

        ProjectDependencies project = new ProjectDependencies();
        project.addStarter(webStarter);
        project.addStarter(testStarter);
        project.printResolved();
    }
}

